<script setup>
import { computed, ref } from "vue";
import { useRoute } from "vue-router";
import MainLayout from "@/components/layout/MainLayout.vue";
import { residents, invoiceHistory, paymentHistory } from "@/stores/resident";

const route = useRoute();
const activeTab = ref("invoices");

const mockResidents = residents.map((resident) => {
  const invoices = (invoiceHistory[resident.id] || []).map((invoice) => ({
    invoiceNo: invoice.id,
    billingMonth: invoice.billingMonth,
    dueDate: invoice.dueDate,
    amount: invoice.amount,
    status: invoice.status,
  }));

  const payments = (paymentHistory[resident.id] || []).map((payment) => ({
    receiptNo: payment.receiptNo,
    paymentDate: payment.date,
    amount: payment.amount,
    method: payment.method,
    reference: payment.id,
  }));

  const totalPaid = payments.reduce((sum, payment) => sum + payment.amount, 0);
  const monthlyFee =
    invoices.length > 0 ? invoices[invoices.length - 1].amount : 0;

  return {
    id: resident.residentCode,
    residentId: resident.id,
    name: resident.name,
    residentCode: resident.residentCode,
    unitCode: resident.unitCode,
    residentType: resident.residentType,
    paymentStatus: resident.paymentStatus,
    phone: resident.phone,
    email: resident.email,
    lineId: "-",
    emergencyContact: resident.emergencyContact,
    emergencyPhone: resident.emergencyPhone,
    moveInDate: resident.moveInDate,
    contractEndDate: "-",
    address: resident.address,
    note: resident.note,
    totalPaid,
    outstandingBalance: resident.outstanding,
    monthlyFee,
    lastPaymentDate: resident.lastPaymentDate,
    houseNo: resident.houseNo,
    building: resident.building,
    zone: resident.zone,
    occupancyStatus: resident.occupancyStatus,
    invoices,
    payments,
  };
});

const residentId = computed(() => String(route.params.id || "").toUpperCase());

const resident = computed(
  () =>
    mockResidents.find((item) => item.id.toUpperCase() === residentId.value) ||
    null,
);

const invoiceItems = computed(() => resident.value?.invoices || []);
const paymentItems = computed(() => resident.value?.payments || []);

const residentTypeText = (type) =>
  ({ owner: "เจ้าของ", tenant: "ผู้เช่า" }[type] || "-");

const paymentStatusText = (status) =>
  ({
    paid: "ชำระครบ",
    overdue: "ค้างชำระ",
    partial: "ชำระบางส่วน",
  }[status] || "-");

const paymentStatusClass = (status) =>
  ({
    paid: "bg-success-subtle text-success",
    overdue: "bg-danger-subtle text-danger",
    partial: "bg-warning-subtle text-warning-emphasis",
  }[status] || "bg-secondary-subtle text-secondary");

const invoiceStatusClass = (status) =>
  ({
    paid: "bg-success-subtle text-success",
    overdue: "bg-danger-subtle text-danger",
    partial: "bg-warning-subtle text-warning-emphasis",
  }[status] || "bg-secondary-subtle text-secondary");

const formatCurrency = (value) => {
  return new Intl.NumberFormat("th-TH", {
    style: "currency",
    currency: "THB",
    minimumFractionDigits: 0,
  }).format(value || 0);
};

const formatDate = (value) => {
  if (!value || value === "-") return "-";
  return new Date(value).toLocaleDateString("th-TH", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
};

const showPaymentModal = ref(false);

const paymentAmount = computed(() => {
  const outstanding = resident.value?.outstandingBalance || 0;
  const monthlyFee = resident.value?.monthlyFee || 0;
  return outstanding > 0 ? outstanding : monthlyFee;
});

// ถ้ามีรูปค่อยใส่รูปที่ public/images/payment-qr-demo.png
const paymentQrImage = computed(() => "/images/payment-qr-demo.png");

const openPaymentModal = () => {
  showPaymentModal.value = true;
};

const closePaymentModal = () => {
  showPaymentModal.value = false;
};

const savePaymentModal = () => {
  showPaymentModal.value = false;
  alert("บันทึกเรียบร้อย!");
};
</script>

<template>
  <MainLayout>
    <div class="container-fluid px-0" v-if="resident">
      <!-- Header -->
      <div class="mb-4">
        <div
          class="d-flex flex-column flex-lg-row justify-content-between align-items-lg-center gap-3"
        >
          <div>
            <h4 class="fw-bold mb-1">ยูนิต / บ้าน / ห้อง ของฉัน</h4>
          </div>
          <div>
            <button
              type="button"
              class="btn btn-outline-success rounded-3 border-success-subtle shadow-sm"
