              </div>
            </div>
          </div>
        </div>

        <div class="col-md-6 col-xl-2">
          <div class="card border-0 shadow-sm rounded-4 h-100 stat-card">
            <div class="card-body p-4">
              <div class="d-flex align-items-start justify-content-between">
                <div class="my-auto">
                  <div class="text-muted small mb-2 me-1">ประเภท</div>
                </div>
                <div class="stat-icon bg-success-subtle text-success">
                  <i class="bi bi-house-door"></i>
                </div>
              </div>
              <div class="fw-bold fs-4 mb-1">
                {{ residentTypeText(resident.residentType) }}
              </div>
              <div class="text-muted small">สถานะการพักอาศัยในระบบ</div>
            </div>
          </div>
        </div>

        <div class="col-md-6 col-xl-3">
          <div class="card border-0 shadow-sm rounded-4 h-100 stat-card">
