              </div>
              <div class="text-muted small">ยอดชำระรวมทั้งหมด</div>
            </div>
          </div>
        </div>

        <div class="col-md-6 col-xl-3">
          <div class="card border-0 shadow-sm rounded-4 h-100 stat-card">
            <div class="card-body p-4">
              <div class="d-flex align-items-start justify-content-between">
                <div class="my-auto">
                  <div class="text-muted small mb-2">ยอดค้างปัจจุบัน</div>
                </div>
                <div class="stat-icon bg-warning-subtle text-warning-emphasis">
                  <i class="bi bi-wallet2"></i>
                </div>
              </div>
              <div class="fw-bold fs-4 mb-1">
                {{ formatCurrency(resident.outstandingBalance) }}
              </div>
              <div class="text-muted small">ยอดค้างชำระล่าสุด</div>
            </div>
          </div>
        </div>
      </div>

      <!-- Highlight Status -->
      <div class="row g-4 mb-4">
        <div class="col-12">
          <div class="card border-0 shadow-sm rounded-4 bg-info bg-opacity-10">
            <div class="card-body p-4">
              <div
                class="d-flex flex-column flex-lg-row justify-content-between align-items-lg-center gap-3"
              >
                <div>
                  <div class="fw-bold fs-5 mb-1">สถานะลูกบ้านที่แสดงอยู่</div>
                  <div class="text-muted">
                    สรุปสถานะการชำระเงินและข้อมูลล่าสุดของลูกบ้านตัวอย่าง
