                      :class="paymentStatusClass(resident.paymentStatus)"
                    >
                      {{ paymentStatusText(resident.paymentStatus) }}
                    </span>
                  </div>
                  <div class="text-muted small">
                    ชำระล่าสุด {{ formatDate(resident.lastPaymentDate) }}
