                </div>
              </div>
            </div>
          </div>
        </div>

        <div class="col-xl-4">
          <div class="card border-0 shadow-sm rounded-4 h-100">
            <div class="card-body p-4">
              <div class="section-title mb-3">
                <i class="bi bi-cash-stack me-2 text-success"></i>สรุปการเงิน
              </div>

              <div class="vstack gap-3">
                <div class="summary-box bg-light rounded-4 p-3">
                  <div class="text-muted small">ค่าส่วนกลางรายเดือน</div>
                  <div class="fw-bold fs-5">
                    {{ formatCurrency(resident.monthlyFee) }}
                  </div>
                </div>

                <div class="summary-box bg-light rounded-4 p-3">
                  <div class="text-muted small">ยอดชำระสะสม</div>
                  <div class="fw-bold fs-5 text-success">
