                </div>

                <div class="summary-box bg-light rounded-4 p-3">
                  <div class="text-muted small">สถานะการชำระ</div>
                  <div>
                    <span
                      class="badge rounded-pill px-3 py-2"
                      :class="paymentStatusClass(resident.paymentStatus)"
                    >
                      {{ paymentStatusText(resident.paymentStatus) }}
                    </span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div class="col-xl-4">
          <div class="card border-0 shadow-sm rounded-4 h-100">
            <div class="card-body p-4">
              <div class="section-title mb-3">
                <i class="bi bi-person-vcard me-2 text-info"></i>ข้อมูลโปรไฟล์
              </div>

              <div class="vstack gap-3">
                <div>
                  <div class="text-muted small">ชื่อ-นามสกุล</div>
                  <div class="fw-semibold">{{ resident.name }}</div>
                </div>
                <div>
                  <div class="text-muted small">รหัสลูกบ้าน</div>
                  <div class="fw-semibold">{{ resident.residentCode }}</div>
                </div>
                <div>
                  <div class="text-muted small">ยูนิต</div>
                  <div class="fw-semibold">{{ resident.unitCode }}</div>
                </div>
                <div>
                  <div class="text-muted small">ประเภท</div>
                  <div class="fw-semibold">
                    {{ residentTypeText(resident.residentType) }}
                  </div>
                </div>
                <div>
                  <div class="text-muted small">วันที่เข้าอยู่</div>
                  <div class="fw-semibold">
                    {{ formatDate(resident.moveInDate) }}
                  </div>
                </div>
                <div>
                  <div class="text-muted small">วันสิ้นสุดสัญญา</div>
                  <div class="fw-semibold">
                    {{ formatDate(resident.contractEndDate) }}
                  </div>
                </div>
                <div>
                  <div class="text-muted small">หมายเหตุ</div>
                  <div class="fw-semibold">{{ resident.note || "-" }}</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- Invoice / Payment History -->
      <div class="card border-0 shadow-sm rounded-4 overflow-hidden">
        <div class="card-header bg-white border-0 p-3">
          <ul class="nav nav-pills gap-2">
            <li class="nav-item">
              <button
                type="button"
                class="nav-link rounded-pill px-4"
                :class="
                  activeTab === 'invoices' ? 'active' : 'text-dark bg-light'
