                type="button"
                class="nav-link rounded-pill px-4"
                :class="
                  activeTab === 'payments' ? 'active' : 'text-dark bg-light'
                "
                @click="activeTab = 'payments'"
              >
                <i class="bi bi-cash-coin me-2"></i>ประวัติการชำระเงิน
              </button>
            </li>
          </ul>
        </div>

        <div class="card-body p-4 bg-light-subtle">
          <!-- Invoice History -->
          <div v-if="activeTab === 'invoices'" class="table-responsive">
            <table class="table align-middle mb-0">
              <thead>
                <tr>
                  <th>เลขที่ใบแจ้งหนี้</th>
                  <th>รอบบิล</th>
                  <th>วันครบกำหนด</th>
                  <th class="text-end">จำนวนเงิน</th>
                  <th class="text-center">สถานะ</th>
                </tr>
              </thead>
              <tbody>
                <tr v-for="item in invoiceItems" :key="item.invoiceNo">
                  <td class="fw-semibold">{{ item.invoiceNo }}</td>
                  <td>{{ item.billingMonth }}</td>
                  <td>{{ formatDate(item.dueDate) }}</td>
                  <td class="text-end">{{ formatCurrency(item.amount) }}</td>
                  <td class="text-center">
                    <span
                      class="badge rounded-pill px-3 py-2"
                      :class="invoiceStatusClass(item.status)"
