                  <td>{{ item.method }}</td>
                  <td>{{ item.reference }}</td>
                  <td class="text-end text-success fw-semibold">
                    {{ formatCurrency(item.amount) }}
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
    <div v-else class="container-fluid px-0">
