export const useResidentStore = defineStore("resident", {
  state: () => ({
    filters: {
      search: "",
      residentType: "",
      paymentStatus: "",
    },
    residents,
    invoiceHistory,
    paymentHistory,
  }),

  getters: {
    filteredResidents: (state) => {
      const keyword = state.filters.search.trim().toLowerCase();

      return state.residents.filter((resident) => {
        const searchable = [
          resident.residentCode,
          resident.name,
          resident.unitCode,
          resident.houseNo,
          resident.building,
          resident.phone,
          resident.email,
        ]
          .join(" ")
          .toLowerCase();

        const matchesSearch = !keyword || searchable.includes(keyword);
        const matchesType =
          !state.filters.residentType ||
          resident.residentType === state.filters.residentType;
        const matchesPaymentStatus =
          !state.filters.paymentStatus ||
          resident.paymentStatus === state.filters.paymentStatus;

        return matchesSearch && matchesType && matchesPaymentStatus;
      });
    },

    totalResidents: (state) => state.residents.length,
    ownerCount: (state) =>
      state.residents.filter((item) => item.residentType === "owner").length,
    tenantCount: (state) =>
      state.residents.filter((item) => item.residentType === "tenant").length,
    overdueCount: (state) =>
      state.residents.filter((item) => item.paymentStatus === "overdue").length,
    totalOutstanding: (state) =>
      state.residents.reduce((sum, item) => sum + item.outstanding, 0),

    residentTypeOptions: () => [
      { label: "ทั้งหมด", value: "" },
      { label: "เจ้าของ", value: "owner" },
      { label: "ผู้เช่า", value: "tenant" },
    ],

    paymentStatusOptions: () => [
      { label: "ทั้งหมด", value: "" },
      { label: "ชำระแล้ว", value: "paid" },
      { label: "ชำระบางส่วน", value: "partial" },
      { label: "ค้างชำระ", value: "overdue" },
    ],

    getResidentById: (state) => (id) =>
      state.residents.find((item) => item.id === Number(id)) || null,
    getInvoicesByResidentId: (state) => (id) =>
      state.invoiceHistory[Number(id)] || [],
    getPaymentsByResidentId: (state) => (id) =>
      state.paymentHistory[Number(id)] || [],
  },

  actions: {
    setSearch(value) {
      this.filters.search = value;
    },
    setResidentType(value) {
      this.filters.residentType = value;
    },
    setPaymentStatus(value) {
      this.filters.paymentStatus = value;
    },
    resetFilters() {
      this.filters.search = "";
      this.filters.residentType = "";
      this.filters.paymentStatus = "";
    },
    addResident(payload) {
      const nextId =
        this.residents.length > 0
          ? Math.max(...this.residents.map((r) => r.id)) + 1
          : 1;

      const residentCode = `RES-${String(nextId).padStart(3, "0")}`;

      this.residents.push({
        id: nextId,
        residentCode,
        paymentStatus: "paid",
        outstanding: 0,
        lastPaymentDate: null,
        ...payload,
      });

      const auth = useAuthStore();
      auth.syncResidentUsers(this.residents);
    },
    updateResident(payload) {
      const index = this.residents.findIndex(
        (item) => item.id === Number(payload.id),
      );

      if (index !== -1) {
        this.residents[index] = {
          ...this.residents[index],
          ...payload,
        };
      }
    },
  },
});
