export const useUnitStore = defineStore("unit", {
  state: () => ({
    filters: { search: "", unitType: "", paymentStatus: "" },
    units,
    invoiceHistory,
    paymentHistory,
  }),

  getters: {
    filteredUnits: (state) => {
      const keyword = state.filters.search.trim().toLowerCase();
      return state.units.filter((unit) => {
        const matchesSearch =
          !keyword ||
          unit.unitCode.toLowerCase().includes(keyword) ||
          unit.houseNo.toLowerCase().includes(keyword) ||
          unit.building.toLowerCase().includes(keyword) ||
          unit.zone.toLowerCase().includes(keyword) ||
          (unit.residentName || "").toLowerCase().includes(keyword);
        const matchesType =
          !state.filters.unitType || unit.unitType === state.filters.unitType;
        const matchesPaymentStatus =
          !state.filters.paymentStatus ||
          unit.paymentStatus === state.filters.paymentStatus;
        return matchesSearch && matchesType && matchesPaymentStatus;
      });
    },
    totalUnits: (state) => state.units.length,
    occupiedUnits: (state) =>
      state.units.filter((u) => u.occupancyStatus === "occupied").length,
    vacantUnits: (state) =>
      state.units.filter((u) => u.occupancyStatus === "vacant").length,
    overdueUnits: (state) =>
      state.units.filter((u) => u.paymentStatus === "overdue").length,
    expectedMonthlyIncome: (state) =>
      state.units.reduce((sum, u) => sum + u.monthlyFee, 0),
    totalOutstanding: (state) =>
      state.units.reduce((sum, u) => sum + u.balance, 0),
    unitTypeOptions: () => [
      { label: "ทั้งหมด", value: "" },
      { label: "บ้าน", value: "house" },
      { label: "ห้องชุด", value: "condo" },
      { label: "ร้านค้า", value: "shop" },
    ],
    paymentStatusOptions: () => [
      { label: "ทั้งหมด", value: "" },
      { label: "ชำระแล้ว", value: "paid" },
      { label: "ชำระบางส่วน", value: "partial" },
      { label: "ค้างชำระ", value: "overdue" },
      { label: "ว่าง", value: "vacant" },
    ],
    getUnitById: (state) => (id) =>
      state.units.find((u) => u.id === Number(id)) || null,
    getInvoicesByUnitId: (state) => (id) =>
      state.invoiceHistory[Number(id)] || [],
    getPaymentsByUnitId: (state) => (id) =>
      state.paymentHistory[Number(id)] || [],
  },

  actions: {
    setSearch(value) {
      this.filters.search = value;
    },
    setUnitType(value) {
      this.filters.unitType = value;
    },
    setPaymentStatus(value) {
      this.filters.paymentStatus = value;
    },
    resetFilters() {
      this.filters.search = "";
      this.filters.unitType = "";
      this.filters.paymentStatus = "";
    },

    // ✅ เพิ่มยูนิตใหม่
    addUnit(payload) {
      const nextId = this.units.length
        ? Math.max(...this.units.map((u) => u.id)) + 1
        : 1;
      this.units.unshift({
        id: nextId,
        unitCode: payload.unitCode,
        houseNo: payload.houseNo,
        building: payload.building,
        zone: payload.zone || "",
        unitType: payload.unitType,
        area: Number(payload.area) || 0,
        parkingSlots: Number(payload.parkingSlots) || 0,
        monthlyFee: Number(payload.monthlyFee) || 0,
        occupancyStatus: payload.occupancyStatus,
        paymentStatus: "pending",
        residentName: "",
        ownerName: "",
        phone: "",
        email: "",
        moveInDate: null,
        balance: 0,
        lastPaymentDate: null,
        note: payload.note || "",
      });
    },

    // ✅ แก้ไขยูนิต
    updateUnit(payload) {
      const index = this.units.findIndex((u) => u.id === payload.id);
      if (index === -1) return;
      this.units[index] = {
        ...this.units[index],
        unitCode: payload.unitCode,
        houseNo: payload.houseNo,
        building: payload.building,
        zone: payload.zone || "",
        unitType: payload.unitType,
        area: Number(payload.area) || 0,
        parkingSlots: Number(payload.parkingSlots) || 0,
        monthlyFee: Number(payload.monthlyFee) || 0,
        occupancyStatus: payload.occupancyStatus,
        note: payload.note || "",
      };
    },
  },
});
