export const useArrearsStore = defineStore('arrears', {
  state: () => ({
    filters: {
      search: '',
      agingGroup: '',
      contactStatus: '',
    },
    arrears,
  }),

  getters: {
    filteredArrears: (state) => {
      const keyword = state.filters.search.trim().toLowerCase()

      return state.arrears.filter((item) => {
        const searchable = [
          item.invoiceNo,
          item.residentName,
          item.unitCode,
          item.building,
          item.billingMonth,
          item.note,
        ]
          .join(' ')
          .toLowerCase()

        const matchesSearch = !keyword || searchable.includes(keyword)
        const matchesAging = !state.filters.agingGroup || item.agingGroup === state.filters.agingGroup
        const matchesContactStatus = !state.filters.contactStatus || item.contactStatus === state.filters.contactStatus

        return matchesSearch && matchesAging && matchesContactStatus
      })
    },

    totalCases: (state) => state.arrears.length,
    totalOutstanding: (state) => state.arrears.reduce((sum, item) => sum + item.totalOutstanding, 0),
    urgentCases: (state) => state.arrears.filter((item) => ['61_90', '90_plus'].includes(item.agingGroup)).length,
    escalatedCases: (state) => state.arrears.filter((item) => ['escalated', 'legal_review'].includes(item.contactStatus)).length,

    agingGroupOptions: () => [
      { label: 'ทั้งหมด', value: '' },
      { label: '1 - 30 วัน', value: '1_30' },
      { label: '31 - 60 วัน', value: '31_60' },
      { label: '61 - 90 วัน', value: '61_90' },
      { label: 'มากกว่า 90 วัน', value: '90_plus' },
    ],

    contactStatusOptions: () => [
      { label: 'ทั้งหมด', value: '' },
      { label: 'ยังไม่ติดตาม', value: 'new' },
      { label: 'ติดตามแล้ว', value: 'contacted' },
      { label: 'รับปากจะชำระ', value: 'promise_to_pay' },
      { label: 'ส่งต่อผู้บริหาร', value: 'escalated' },
      { label: 'อยู่ระหว่างพิจารณากฎหมาย', value: 'legal_review' },
    ],

    summaryByAging: (state) => {
      const groups = {
        '1_30': 0,
        '31_60': 0,
        '61_90': 0,
        '90_plus': 0,
      }
      state.arrears.forEach((item) => {
        groups[item.agingGroup] += item.totalOutstanding
      })
      return groups
    },
  },

  actions: {
    setSearch(value) {
      this.filters.search = value
    },
    setAgingGroup(value) {
      this.filters.agingGroup = value
    },
    setContactStatus(value) {
      this.filters.contactStatus = value
    },
    resetFilters() {
      this.filters.search = ''
      this.filters.agingGroup = ''
      this.filters.contactStatus = ''
    },
  },
})
