const paymentMethods = [
  { label: "เงินสด", value: "cash", icon: "bi-cash" },
  { label: "โอนธนาคาร", value: "bank_transfer", icon: "bi-bank" },
  { label: "QR Payment", value: "qr_payment", icon: "bi-qr-code" },
  { label: "บัตรเครดิต", value: "credit_card", icon: "bi-credit-card" },
];

export const usePaymentStore = defineStore("payment", {
  state: () => ({
    filters: {
      search: "",
      method: "",
      status: "",
    },
    payments,
    paymentEvents,
    pendingInvoices,
    paymentMethods,
    submitting: false,
  }),

  getters: {
    filteredPayments: (state) => {
      const keyword = state.filters.search.trim().toLowerCase();

      return state.payments.filter((payment) => {
        const searchable = [
          payment.paymentNo,
          payment.invoiceNo,
          payment.residentName,
          payment.unitCode,
          payment.building,
          payment.receiptNo,
          payment.recordedBy,
        ]
          .join(" ")
          .toLowerCase();

        const matchesSearch = !keyword || searchable.includes(keyword);
        const matchesMethod =
          !state.filters.method || payment.method === state.filters.method;
        const matchesStatus =
          !state.filters.status || payment.status === state.filters.status;

        return matchesSearch && matchesMethod && matchesStatus;
      });
    },

    totalPayments: (state) => state.payments.length,
    completedPayments: (state) =>
      state.payments.filter((item) => item.status === "completed").length,
    partialPayments: (state) =>
      state.payments.filter((item) => item.status === "partial").length,
    pendingVerifyPayments: (state) =>
      state.payments.filter((item) => item.status === "pending_verify").length,
    totalCollected: (state) =>
      state.payments.reduce((sum, item) => sum + item.amount, 0),

    methodOptions: () => [
      { label: "ทั้งหมด", value: "" },
      { label: "เงินสด", value: "cash" },
      { label: "โอนธนาคาร", value: "bank_transfer" },
      { label: "QR Payment", value: "qr_payment" },
      { label: "บัตรเครดิต", value: "credit_card" },
    ],

    statusOptions: () => [
      { label: "ทั้งหมด", value: "" },
      { label: "รับชำระสมบูรณ์", value: "completed" },
      { label: "ชำระบางส่วน", value: "partial" },
      { label: "รอตรวจสอบ", value: "pending_verify" },
    ],

    paymentFormInvoiceOptions: (state) =>
      state.pendingInvoices.map((item) => ({
        label: `${item.invoiceNo} • ${
          item.residentName
        } • คงเหลือ ${new Intl.NumberFormat("th-TH", {
          style: "currency",
          currency: "THB",
          minimumFractionDigits: 0,
        }).format(item.outstandingAmount)}`,
        value: item.invoiceNo,
      })),

    getPaymentById: (state) => (id) =>
      state.payments.find((item) => item.id === Number(id)) || null,
    getEventsByPaymentId: (state) => (id) =>
      state.paymentEvents[Number(id)] || [],
    getInvoiceByNo: (state) => (invoiceNo) =>
      state.pendingInvoices.find((item) => item.invoiceNo === invoiceNo) ||
      null,
  },

  actions: {
    setSearch(value) {
      this.filters.search = value;
    },
    setMethod(value) {
      this.filters.method = value;
    },
    setStatus(value) {
      this.filters.status = value;
    },
    resetFilters() {
      this.filters.search = "";
      this.filters.method = "";
      this.filters.status = "";
    },

    async createPayment(payload) {
      this.submitting = true;
      await new Promise((resolve) => setTimeout(resolve, 700));

      const nextId = this.payments.length
        ? Math.max(...this.payments.map((item) => item.id)) + 1
        : 1;
      const nextRunning = String(nextId).padStart(4, "0");
      const now = new Date();
      const paymentNo = `PAY-${now.getFullYear()}-${nextRunning}`;
      const receiptNo = payload.generateReceipt
        ? `RC-${now.getFullYear()}-${nextRunning}`
        : "-";

      const invoice = this.getInvoiceByNo(payload.invoiceNo);
      const newPayment = {
        id: nextId,
        paymentNo,
        invoiceNo: payload.invoiceNo,
        paymentDate: payload.paymentDate,
        residentName: invoice?.residentName || "-",
        unitCode: invoice?.unitCode || "-",
        building: invoice?.building || "-",
        amount: Number(payload.amount || 0),
        method: payload.method,
        status: payload.status,
        receiptNo,
        recordedBy: "Current User",
        referenceNo: payload.referenceNo || "-",
        bankName: payload.bankName || "-",
        verifiedBy:
          payload.status === "pending_verify" ? "-" : "Finance Supervisor",
        verifiedAt:
          payload.status === "pending_verify"
            ? "-"
            : `${payload.paymentDate} 15:00`,
        note: payload.note || "",
      };

      this.payments.unshift(newPayment);
      this.paymentEvents[nextId] = [
        {
          id: 1,
          time: `${payload.paymentDate} 14:45`,
          title: "สร้างรายการรับชำระ",
          description: "สร้างรายการจากหน้าฟอร์มรับชำระเงิน",
        },
      ];

      this.submitting = false;
      return { success: true, id: nextId };
    },
    updatePayment(payload) {
      const index = this.payments.findIndex((p) => p.id === payload.id);
      if (index === -1) return;

      const prev = this.payments[index];

      this.payments[index] = {
        ...prev,
        paymentDate: payload.paymentDate,
        amount: Number(payload.amount),
        method: payload.method,
        bankName: payload.bankName || "-",
        referenceNo: payload.referenceNo || "-",
        status: payload.status,
        receiptNo: payload.receiptNo || "-",
        note: payload.note || "",
        // อัปเดต verifiedBy/verifiedAt ตามสถานะใหม่
        verifiedBy:
          payload.status === "pending_verify"
            ? "-"
            : prev.verifiedBy !== "-"
            ? prev.verifiedBy
            : "Finance Supervisor",
        verifiedAt:
          payload.status === "pending_verify"
            ? "-"
            : prev.verifiedAt !== "-"
            ? prev.verifiedAt
            : `${payload.paymentDate} 15:00`,
      };

      // เพิ่ม timeline event ว่ามีการแก้ไข
      const events = this.paymentEvents[payload.id] || [];
      const now = new Date();
      const timeStr = `${now.getFullYear()}-${String(
        now.getMonth() + 1,
      ).padStart(2, "0")}-${String(now.getDate()).padStart(2, "0")} ${String(
        now.getHours(),
      ).padStart(2, "0")}:${String(now.getMinutes()).padStart(2, "0")}`;

      this.paymentEvents[payload.id] = [
        ...events,
        {
          id: events.length + 1,
          time: timeStr,
          title: "แก้ไขรายการรับชำระ",
          description: `แก้ไขข้อมูลโดย Current User — สถานะ: ${payload.status}`,
        },
      ];
    },
  },
});
