export const useInvoiceStore = defineStore("invoice", {
  state: () => ({
    filters: {
      search: "",
      status: "",
      billingMonth: "",
    },
    invoices,
    invoiceLineItems,
    paymentHistory,
  }),

  getters: {
    filteredInvoices: (state) => {
      const keyword = state.filters.search.trim().toLowerCase();

      return state.invoices.filter((invoice) => {
        const searchable = [
          invoice.invoiceNo,
          invoice.billingMonth,
          invoice.unitCode,
          invoice.residentName,
          invoice.building,
        ]
          .join(" ")
          .toLowerCase();

        const matchesSearch = !keyword || searchable.includes(keyword);
        const matchesStatus =
          !state.filters.status || invoice.status === state.filters.status;
        const matchesBillingMonth =
          !state.filters.billingMonth ||
          invoice.billingMonth === state.filters.billingMonth;

        return matchesSearch && matchesStatus && matchesBillingMonth;
      });
    },

    totalInvoices: (state) => state.invoices.length,
    paidInvoices: (state) =>
      state.invoices.filter((item) => item.status === "paid").length,
    overdueInvoices: (state) =>
      state.invoices.filter((item) => item.status === "overdue").length,
    pendingInvoices: (state) =>
      state.invoices.filter((item) => item.status === "pending").length,
    totalRevenue: (state) =>
      state.invoices.reduce((sum, item) => sum + item.paidAmount, 0),
    totalOutstanding: (state) =>
      state.invoices.reduce(
        (sum, item) => sum + (item.totalAmount - item.paidAmount),
        0,
      ),

    statusOptions: () => [
      { label: "ทั้งหมด", value: "" },
      { label: "รอชำระ", value: "pending" },
      { label: "ชำระบางส่วน", value: "partial" },
      { label: "ชำระแล้ว", value: "paid" },
      { label: "ค้างชำระ", value: "overdue" },
    ],

    billingMonthOptions: (state) => {
      const months = [
        ...new Set(state.invoices.map((item) => item.billingMonth)),
      ];
      return [
        { label: "ทั้งหมด", value: "" },
        ...months.map((month) => ({ label: month, value: month })),
      ];
    },

    getInvoiceById: (state) => (id) =>
      state.invoices.find((item) => item.id === Number(id)) || null,
    getLineItemsByInvoiceId: (state) => (id) =>
      state.invoiceLineItems[Number(id)] || [],
    getPaymentsByInvoiceId: (state) => (id) =>
      state.paymentHistory[Number(id)] || [],
  },

  actions: {
    setSearch(value) {
      this.filters.search = value;
    },
    setStatus(value) {
      this.filters.status = value;
    },
    setBillingMonth(value) {
      this.filters.billingMonth = value;
    },
    resetFilters() {
      this.filters.search = "";
      this.filters.status = "";
      this.filters.billingMonth = "";
    },
    addInvoice(payload) {
      const nextId = this.invoices.length
        ? Math.max(...this.invoices.map((i) => i.id)) + 1
        : 1;

      const running = String(nextId).padStart(4, "0");
      const year = new Date().getFullYear();

      const totalAmount =
        Number(payload.amount || 0) + Number(payload.penalty || 0);

      this.invoices.unshift({
        id: nextId,
        invoiceNo: `INV-${year}-${running}`,
        billingMonth: payload.billingMonth,
        unitCode: payload.unitCode,
        residentName: payload.residentName,
        building: payload.building,
        issueDate: payload.issueDate,
        dueDate: payload.dueDate,
        amount: Number(payload.amount) || 0,
        penalty: Number(payload.penalty) || 0,
        totalAmount,
        paidAmount: 0,
        status: "pending",
        note: payload.note || "",
      });

      // เพิ่ม line items อัตโนมัติ
      const items = [
        {
          id: 1,
          description: `ค่าส่วนกลางประจำเดือน ${payload.billingMonth}`,
          qty: 1,
          unitPrice: Number(payload.amount),
          amount: Number(payload.amount),
        },
      ];
      if (Number(payload.penalty) > 0) {
        items.push({
          id: 2,
          description: "ค่าปรับล่าช้า",
          qty: 1,
          unitPrice: Number(payload.penalty),
          amount: Number(payload.penalty),
        });
      }
      this.invoiceLineItems[nextId] = items;
    },
    updateInvoice(payload) {
      const index = this.invoices.findIndex((i) => i.id === payload.id);
      if (index === -1) return;
      const totalAmount =
        Number(payload.amount || 0) + Number(payload.penalty || 0);
      this.invoices[index] = {
        ...this.invoices[index],
        billingMonth: payload.billingMonth,
        unitCode: payload.unitCode,
        residentName: payload.residentName,
        building: payload.building,
        issueDate: payload.issueDate,
        dueDate: payload.dueDate,
        amount: Number(payload.amount) || 0,
        penalty: Number(payload.penalty) || 0,
        totalAmount,
        note: payload.note || "",
      };
    },
  },
});
