export const useReportStore = defineStore('report', {
  state: () => ({
    filters: {
      year: '2026',
      project: 'all',
    },
    projectOptions: [
      { label: 'ทุกโครงการ', value: 'all' },
      { label: 'Central Fee Residence', value: 'central-fee-residence' },
      { label: 'Central Fee Tower', value: 'central-fee-tower' },
    ],
    years: ['2026', '2025'],
    yearlySummaries,
    monthlyRevenue,
    channelCollections,
    agingSummary,
    reportHighlights,
  }),

  getters: {
    selectedYear: (state) => state.filters.year,

    summary: (state) => state.yearlySummaries[state.filters.year] || {
      totalRevenue: 0,
      totalInvoiced: 0,
      collectionRate: 0,
      overdueAmount: 0,
      occupiedUnits: 0,
      activeResidents: 0,
    },

    revenueTrend: (state) => state.monthlyRevenue[state.filters.year] || [],
    collectionByChannel: (state) => state.channelCollections[state.filters.year] || [],
    arrearsAging: (state) => state.agingSummary[state.filters.year] || [],
    highlights: (state) => state.reportHighlights[state.filters.year] || [],

    collectionGap: (state) => {
      const summary = state.yearlySummaries[state.filters.year]
      if (!summary) return 0
      return Math.max(summary.totalInvoiced - summary.totalRevenue, 0)
    },
  },

  actions: {
    setYear(value) {
      this.filters.year = value
    },
    setProject(value) {
      this.filters.project = value
    },
  },
})

